import{c,$ as l,Q as o,j as h,m as d,h as a,ax as t,n,o as s,S as r}from"./chunks/framework.CAKLAi0D.js";const u="/_pr/500/assets/2026-04-24-nyldn-claude-octopus-cover.CDX0BVhN.webp",k=JSON.parse('{"title":"No PR Required: How claude-octopus Closed 23 Findings Before the Weekend — and Left Two Doors Unlocked","description":"","frontmatter":{},"headers":[],"relativePath":"case-studies/2026-04-24-nyldn-claude-octopus.md","filePath":"case-studies/2026-04-24-nyldn-claude-octopus.md","lastUpdated":null}'),p={name:"case-studies/2026-04-24-nyldn-claude-octopus.md"};function m(f,e,g,b,w,y){const i=l("Mermaid");return o(),h("div",null,[e[2]||(e[2]=d('<h1 id="no-pr-required-how-claude-octopus-closed-23-findings-before-the-weekend-—-and-left-two-doors-unlocked" tabindex="-1">No PR Required: How claude-octopus Closed 23 Findings Before the Weekend — and Left Two Doors Unlocked <a class="header-anchor" href="#no-pr-required-how-claude-octopus-closed-23-findings-before-the-weekend-—-and-left-two-doors-unlocked" aria-label="Permalink to &quot;No PR Required: How claude-octopus Closed 23 Findings Before the Weekend — and Left Two Doors Unlocked&quot;">​</a></h1><p><img src="'+u+'" alt="Cover"></p><blockquote><p><strong>Disclosure</strong>: This article was generated by an automated pipeline using Claude (Sonnet 4.6) based on audit data and GitHub records. It describes work performed by NLPM tooling maintained by <a href="https://github.com/xiaolai" target="_blank" rel="noreferrer">xiaolai</a>. Readers should weigh claims accordingly.</p></blockquote><hr><h2 id="the-project" tabindex="-1">The Project <a class="header-anchor" href="#the-project" aria-label="Permalink to &quot;The Project&quot;">​</a></h2><p><a href="https://github.com/nyldn/claude-octopus" target="_blank" rel="noreferrer">claude-octopus</a> is a Claude Code plugin by <a href="https://github.com/nyldn" target="_blank" rel="noreferrer">Chris S</a> that routes every coding task to up to eight AI models in parallel — Claude, Gemini, Codex, and others — so blind spots surface before they ship — like running every blueprint past eight independent reviewers before signing off. With 2,820 stars and 266 forks, it is among the most-starred Claude Code plugins in active development. The repository ships 157 NL artifacts across nine categories: GitHub Actions agents, personas, droids, skill-router agents, principles, default subagents, commands, skills, and provider/workflow config.</p><hr><h2 id="the-audit" tabindex="-1">The Audit <a class="header-anchor" href="#the-audit" aria-label="Permalink to &quot;The Audit&quot;">​</a></h2><p>NLPM audited nyldn/claude-octopus on 2026-04-16 against 157 artifacts. The weighted score was <strong>79/100</strong> — above the default 70-point threshold but below the 85 default threshold that unlocks automatic contribution (configurable per project). The recommendation was REVIEW: contribution was blocked pending resolution of two HIGH security findings. A passing grade with unfinished homework.</p>',9)),(o(),a(r,null,{default:t(()=>[s(i,{id:"mermaid-25",class:"mermaid-diagram",graph:"pie%20title%20Finding%20Distribution%20at%20Audit%20(26%20total)%0A%20%20%20%20%22Quality%20Issues%22%20%3A%2014%0A%20%20%20%20%22Bugs%22%20%3A%206%0A%20%20%20%20%22Security%20Findings%22%20%3A%206%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=d(`<p>Score breakdown by category at the time of audit:</p><table tabindex="0"><thead><tr><th>Category</th><th>Files</th><th>Avg Score</th><th>Notes</th></tr></thead><tbody><tr><td><code>.github/agents/</code></td><td>10</td><td>63</td><td>Minimal stubs, systemic bugs</td></tr><tr><td><code>agents/droids/</code></td><td>10</td><td>78</td><td>Missing <code>tools</code> throughout</td></tr><tr><td><code>agents/skills/</code></td><td>3</td><td>72</td><td>Thin, minimal descriptions</td></tr><tr><td><code>.claude/commands/</code></td><td>49</td><td>74</td><td>~65% missing <code>allowed-tools</code></td></tr><tr><td><code>config/</code></td><td>8</td><td>80</td><td>No frontmatter schema</td></tr><tr><td><code>agents/principles/</code></td><td>4</td><td>82</td><td>Clean format</td></tr><tr><td><code>.claude/agents/</code></td><td>10</td><td>84</td><td>Stable, missing examples</td></tr><tr><td><code>agents/personas/</code></td><td>32</td><td>85</td><td>Well-formed; 40% missing <code>tools</code></td></tr><tr><td><code>skills/</code></td><td>29</td><td>85</td><td>Strong execution contracts</td></tr><tr><td><strong>Overall</strong></td><td><strong>157</strong></td><td><strong>79</strong></td><td></td></tr></tbody></table><p><strong>Top issues by severity:</strong></p><p><strong>HIGH — blocks contribution:</strong></p><ul><li><p><strong>FINDING-01:</strong> <code>agents/personas/openclaw-admin.md</code> contained <code>curl -fsSL https://gogcli.sh/install.sh | bash</code>. The domain <code>gogcli.sh</code> did not match the rest of the codebase (which references <code>openclaw.ai</code>), making this both a curl-pipe-sh risk and a domain mismatch bug (BUG-006). If the openclaw-admin persona followed its own installation instructions, it would download and execute code from an unverified third-party domain.</p></li><li><p><strong>FINDING-02:</strong> <code>skills/skill-claw/SKILL.md</code> contained three instances of <code>curl -fsSL https://openclaw.ai/install.sh | bash</code> in its installation table and code block, with no hash verification or user inspection gate. If Claude follows the installation workflow, it would execute this pattern without content inspection.</p></li></ul><p><strong>BUG-level (functional breakage):</strong></p><ul><li><p><strong>BUG-001:</strong> All 10 <code>.github/agents/</code> files declared <code>readonly: true</code> in their frontmatter while their body text required write and execute tools — a read-only vs. write-intent conflict. Whether Claude Code enforces <code>readonly: true</code> as a recognized frontmatter constraint (vs. silently ignoring unknown frontmatter keys) is unverified; if the field is ignored, the agents simply lack any explicit access control — a lock that may or may not be wired to anything. A separate tool-name casing issue — <code>read</code>, <code>search</code>, <code>execute</code> instead of <code>Read</code>, <code>Glob</code>/<code>Grep</code>, <code>Bash</code> — surfaced as an introduced finding at re-audit once the original fingerprint was resolved; it is not the original BUG-001.</p></li><li><p><strong>BUG-002:</strong> All 10 <code>agents/droids/</code> files had no <code>tools:</code> field. Without this declaration, Claude Code defaults to an empty tool list, and the droids — which describe complex task-execution workflows — could only produce text output.</p></li><li><p><strong>BUG-005:</strong> <code>hooks/user-prompt-submit.sh</code> used <code>python3</code> for JSON parsing with no fallback for environments where Python 3 is absent.</p></li></ul><p><strong>Systemic quality gaps:</strong> ~32 of 49 <code>.claude/commands/</code> files were missing <code>allowed-tools</code> declarations. Roughly 13 of 32 personas lacked <code>tools:</code> fields, creating a silent quality split: personas with tools worked correctly as subagents; personas without them silently restricted to text generation, with no visible difference from the user&#39;s perspective.</p><hr><h2 id="what-was-submitted" tabindex="-1">What Was Submitted <a class="header-anchor" href="#what-was-submitted" aria-label="Permalink to &quot;What Was Submitted&quot;">​</a></h2><p>NLPM did not submit any pull requests in this engagement. The pipeline filed one issue:</p><table tabindex="0"><thead><tr><th>#</th><th>Title</th><th>URL</th><th>Filed</th><th>Closed</th></tr></thead><tbody><tr><td>#298</td><td>NLPM Audit Report: 6 bugs and 6 security findings (score: 79/100)</td><td><a href="https://github.com/nyldn/claude-octopus/issues/298" target="_blank" rel="noreferrer">link</a></td><td>2026-04-20</td><td>2026-04-22</td></tr></tbody></table><p>The issue reported all six bugs, six security findings, and fourteen quality issues with suggested fixes and diff examples. Sometimes the most useful contribution is a well-aimed report and a step back.</p><hr><h2 id="the-response" tabindex="-1">The Response <a class="header-anchor" href="#the-response" aria-label="Permalink to &quot;The Response&quot;">​</a></h2><p>Issue #298 was filed at 18:31 UTC on 2026-04-20. Less than ten hours later — no comment filed, no acknowledgment posted, just a release — nyldn shipped <a href="https://github.com/nyldn/claude-octopus/commit/1ab6b1d6874b392180cb7e70546c68d61fb9fd65" target="_blank" rel="noreferrer">v9.26.0</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>release: v9.26.0 — opus dispatch fix, NLPM audit fixes, qwen flag, webhook HTTPS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- fix(agents): add tools declarations to 10 droids + python-pro (#298)</span></span>
<span class="line"><span>- fix(skill-extract): beta status caveat in description (#298)</span></span>
<span class="line"><span>- fix(hooks): jq fallback when python3 absent (#298)</span></span>
<span class="line"><span>- fix(security): reject non-HTTPS webhook URLs (#298)</span></span></code></pre></div><p>Four of six fix lines cite the audit issue directly. The droid tools declarations, the skill-extract beta caveat, the Python fallback in the hooks, and webhook HTTPS enforcement all shipped in a single release. The webhook HTTPS enforcement corresponds to FINDING-03, a MEDIUM security finding from the original audit; it is resolved in v9.26.0. The maintainer also opened four separate PRs (#293–#296) addressing individual findings as discrete changes. Because these PR numbers are lower than issue #298 (GitHub issues and PRs share a single sequence), they may have been opened before the audit issue was filed; if so, the work was already in progress independently rather than triggered by the audit. In open source, it&#39;s perfectly fine to arrive second with the right diagnosis. Issue #298 closed on 2026-04-22 — 35 hours after it was filed.</p><p>No maintainer review comments are on record. The response was direct commits and self-authored PRs rather than inline discussion. It is possible the fixes were already in progress and the audit timing was coincidental; no maintainer statement confirms or denies that.</p><p>Between the issue filing and the re-audit, nyldn shipped three additional releases — <a href="https://github.com/nyldn/claude-octopus/commit/fefcb24dce7cea05ffb06cbdae44311c926e9835" target="_blank" rel="noreferrer">v9.28.0</a> (2026-04-22), <a href="https://github.com/nyldn/claude-octopus/commit/bd827dfa1f49aefa63e53941f8ee6d58d7e880fe" target="_blank" rel="noreferrer">v9.29.1</a> (2026-04-22), and <a href="https://github.com/nyldn/claude-octopus/commit/997a26558c6e96a745918c66bd4e4f686ae73b41" target="_blank" rel="noreferrer">v9.29.2</a> (2026-04-23) — incorporating hook hardening, output cap fixes, and model-config improvements that were independent of the audit. The project&#39;s cadence — four releases across two days — provides important context: the &quot;less than ten hours&quot; response may reflect the normal pace of an actively shipping codebase rather than an exceptional reaction to the audit.</p><hr><h2 id="the-re-audit" tabindex="-1">The Re-Audit <a class="header-anchor" href="#the-re-audit" aria-label="Permalink to &quot;The Re-Audit&quot;">​</a></h2><p>A rubric score update is a claim about quality at a point in time; the re-audit verifies that claim against the target repo&#39;s current HEAD. Think of it as checking whether the photograph still resembles its subject.</p><p>The re-audit ran on 2026-04-24 against commit <code>14e8ee4</code> (<code>14e8ee4ee502e2fc4441eb13d7def4c80892fc82</code>). The baseline commit SHA was not recorded. The score moved from <strong>79 → 82</strong> (+3) across 127 artifacts (down from 157 at audit, as the repo evolved between snapshots). The modest +3 gain reflects that 12 introduced findings offset most of the gains from the 23 resolved ones — illustrating how scoring drift can produce an appearance of resolution without proportional score improvement.</p><h3 id="per-finding-outcome-table" tabindex="-1">Per-Finding Outcome Table <a class="header-anchor" href="#per-finding-outcome-table" aria-label="Permalink to &quot;Per-Finding Outcome Table&quot;">​</a></h3><p>The outcome column is reproduced verbatim from the verification data. For findings listed with a PR number, the fix was applied via a maintainer-authored PR. For findings without a PR, the fix reached HEAD through direct commits or squashed merges.</p><p>Verification is fingerprint-based: a finding is marked &quot;fixed&quot; when its original content fingerprint no longer matches any file at HEAD. A finding can resolve this way without the underlying risk being eliminated — if the same pattern recurs in a refactored or renamed file, it registers as a new introduced finding rather than a persisting original.</p><table tabindex="0"><thead><tr><th>#</th><th>File</th><th>Rule</th><th>Outcome</th><th>PR</th></tr></thead><tbody><tr><td>1</td><td><code>code-reviewer.md</code></td><td>BUG-read-only-write</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>2</td><td><code>performance-engineer.md</code></td><td>BUG-read-only-write</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>3</td><td><code>cloud-architect.md</code></td><td>BUG-read-only-write</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>4</td><td><code>.github/agents/</code></td><td>BUG-read-only-write</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>5</td><td><code>agents/droids/</code></td><td>BUG-unclassified</td><td>fixed — applied separately</td><td>#293</td></tr><tr><td>6</td><td><code>agents/personas/python-pro.md</code></td><td>BUG-unclassified</td><td>fixed — applied separately</td><td>#294</td></tr><tr><td>7</td><td><code>skills/skill-extract/SKILL.md</code></td><td>BUG-unclassified</td><td>fixed — applied separately</td><td>#295</td></tr><tr><td>8</td><td><code>hooks/user-prompt-submit.sh</code></td><td>BUG-unclassified</td><td>fixed — applied separately</td><td>#296</td></tr><tr><td>9</td><td><code>agents/personas/openclaw-admin.md</code></td><td>SEC-curl-pipe-sh</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>10</td><td><code>.github/agents/</code> stubs (~63/100)</td><td>UNCLASSIFIED</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>11</td><td><code>.claude/commands/</code> missing <code>allowed-tools</code></td><td>BUG-undeclared-tool</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>12</td><td>Vague quantifiers in skill descriptions</td><td>R01</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>13</td><td><code>devops-troubleshooter.md</code> missing <code>tools</code></td><td>BUG-undeclared-tool</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>14</td><td><code>incident-responder.md</code> missing <code>tools</code></td><td>BUG-undeclared-tool</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>15</td><td><code>test-automator.md</code> missing <code>tools</code></td><td>BUG-undeclared-tool</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>16</td><td><code>cloud-architect.md</code> missing <code>tools</code></td><td>BUG-undeclared-tool</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>17</td><td><code>mermaid-expert.md</code> haiku with no tools</td><td>UNCLASSIFIED</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>18</td><td><code>context-manager.md</code> missing when_to_use/examples</td><td>UNCLASSIFIED</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>19</td><td><code>ai-engineer.md</code> missing when_to_use/examples</td><td>UNCLASSIFIED</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>20</td><td><code>academic-writer.md</code>, <code>graphql-architect.md</code> missing <code>tools</code></td><td>UNCLASSIFIED</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>21</td><td><code>config/</code> files lack NLPM frontmatter schema</td><td>UNCLASSIFIED</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>22</td><td><code>business-analyst.md</code>, <code>exec-communicator.md</code> no <code>tools</code></td><td>UNCLASSIFIED</td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>23</td><td><code>skill-extract/SKILL.md</code> skeleton not gated by capability check</td><td>UNCLASSIFIED</td><td>fixed — upstream, not via our PR</td><td></td></tr></tbody></table><p><strong>All 23 original fingerprints resolved.</strong> The curl-pipe-sh risk flagged in FINDING-01 and FINDING-02 persists under new fingerprints and is captured in the introduced findings below.</p><h3 id="introduced-findings" tabindex="-1">Introduced Findings <a class="header-anchor" href="#introduced-findings" aria-label="Permalink to &quot;Introduced Findings&quot;">​</a></h3><p>The re-audit found 12 findings at HEAD that were not present in the original audit. These may be true regressions from maintainer commits between 2026-04-16 and 2026-04-24, or they may reflect scoring drift — the model re-scoring an evolved artifact set and fingerprinting similar issues differently. Both possibilities apply here; neither should be assumed without additional audit snapshots from the intervening period. Scoring drift is like measuring the same river twice — the water moved, but you still call it the same river.</p><p>Notable introduced findings:</p><ul><li><p><strong>Non-standard tool names in <code>.github/agents/</code> (all 10 files):</strong> All agents declare <code>read</code>, <code>search</code>, <code>execute</code> instead of <code>Read</code>, <code>Glob</code>/<code>Grep</code>, <code>Bash</code>. The original audit&#39;s BUG-001 flagged these agents for <code>readonly: true</code> conflicts; when that was resolved, the tool-name casing problem became the new dominant fingerprint. This is likely scoring drift on a pre-existing issue rather than a regression.</p></li><li><p><strong>Droids <code>tools: [&quot;All tools&quot;]</code> overly broad (QUALITY-007):</strong> This finding is a direct consequence of the BUG-002 fix. Adding tools declarations resolved the original finding, but the batch update used an overly permissive declaration for every droid regardless of operational scope. This is a plausible true regression introduced by the fix itself. However, droids are described as task-specific agents with complex execution needs; &quot;All tools&quot; may also reflect an intentional operational choice by the maintainer. NLPM recommends scoping per R11 (least-privilege tools), but the declaration is technically valid.</p></li><li><p><strong>16 personas still missing <code>tools:</code> (up from 13 in the original audit):</strong> The original QUALITY-013 identified 13 personas. The re-audit count of 16 may include three personas added between audits, or may reflect different fingerprinting of the same underlying gap.</p></li><li><p><strong>42 of 48 commands missing output format, 43 of 48 missing <code>allowed-tools</code>:</strong> These closely mirror findings 11 and 12 in the original audit. They were fingerprinted as resolved (the original fingerprints matched HEAD), but the systemic gaps persist in a form the re-audit re-identified as new. This is the clearest example of scoring drift in this engagement.</p></li></ul><hr><h2 id="what-the-audit-revealed" tabindex="-1">What the Audit Revealed <a class="header-anchor" href="#what-the-audit-revealed" aria-label="Permalink to &quot;What the Audit Revealed&quot;">​</a></h2><h3 id="a-two-tier-personas-layer" tabindex="-1">A two-tier personas layer <a class="header-anchor" href="#a-two-tier-personas-layer" aria-label="Permalink to &quot;A two-tier personas layer&quot;">​</a></h3><p>The 32-persona set had a clean quality split visible only from the outside: ~19 personas with explicit <code>tools:</code> declarations that function correctly as subagents, and ~13 that silently restrict to text-only output. From the user&#39;s perspective, invoking <code>backend-architect</code> gets a full tool suite; invoking <code>cloud-architect</code> gets text generation only. No error surface, no warning — silent capability degradation, like two switches that look identical but only one turns on the lights. The fix (add a <code>tools:</code> field) was mechanical, and the v9.26.0 batch-fix of the 10 droids demonstrated the pattern was executable at scale.</p><h3 id="coordinated-curl-pipe-sh-risk" tabindex="-1">Coordinated curl-pipe-sh risk <a class="header-anchor" href="#coordinated-curl-pipe-sh-risk" aria-label="Permalink to &quot;Coordinated curl-pipe-sh risk&quot;">​</a></h3><p>FINDING-01 and FINDING-02 operated as a coordinated surface: the <code>openclaw-admin</code> persona would guide users through installation, and <code>skill-claw/SKILL.md</code> would execute it. The domain mismatch fix (correcting <code>gogcli.sh</code> to <code>openclaw.ai</code>) resolved BUG-006 and improved correctness, but the curl-pipe-sh execution pattern itself — no hash verification, no download-then-inspect gate — remained in <code>skill-claw/SKILL.md</code> through the re-audit. Both HIGH security findings remain open as of 2026-04-24.</p><h3 id="commands-as-an-unrestricted-surface" tabindex="-1">Commands as an unrestricted surface <a class="header-anchor" href="#commands-as-an-unrestricted-surface" aria-label="Permalink to &quot;Commands as an unrestricted surface&quot;">​</a></h3><p>With ~65% of 49 command files missing <code>allowed-tools</code> at audit time, the commands layer averaged 74/100. Commands like <code>embrace</code>, <code>factory</code>, and <code>parallel</code> that orchestrate multi-provider workflows had unrestricted tool access despite well-defined operational scope. Per R15 (least-privilege tools), this is an unnecessarily wide surface — particularly for commands that invoke <code>orchestrate.sh</code> against external providers. Missing <code>allowed-tools</code> does not grant wider tool access than the session baseline; it removes the explicit scope declaration that aids auditability and restricts sub-invocations. R15 is an NLPM convention, not a Claude Code requirement.</p><h3 id="on-fairness" tabindex="-1">On fairness <a class="header-anchor" href="#on-fairness" aria-label="Permalink to &quot;On fairness&quot;">​</a></h3><p>The audit applied NLPM&#39;s rubric to a project with its own well-established conventions: enforcement hooks, a comprehensive root <code>CLAUDE.md</code>, output caps, and explicit workflow documentation. Several findings — including the <code>config/</code> frontmatter schema gap and the <code>.github/agents/</code> stub-quality penalties — reflect NLPM schema expectations rather than actual dysfunction. The bugs and security findings are correctness issues. The quality issues are a mix of real structural gaps and rubric-alignment gaps; readers should weigh them accordingly. Some findings counted in the 23-fixed set — such as the <code>config/</code> frontmatter schema gap — reflect NLPM convention adoption rather than bug correction; the maintainer who added NLPM-conformant frontmatter was adopting an external standard, not fixing a defect in their own codebase. Similarly, <code>allowed-tools</code> omissions are NLPM convention findings (R15), not violations of any Claude Code specification. Noting that a well-built house doesn&#39;t match your blueprint is not the same as finding cracks in the foundation.</p><hr><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2>`,45)),(o(),a(r,null,{default:t(()=>[s(i,{id:"mermaid-796",class:"mermaid-diagram",graph:"gantt%0A%20%20%20%20title%20nyldn%2Fclaude-octopus%20Audit%20Engagement%0A%20%20%20%20dateFormat%20YYYY-MM-DD%0A%20%20%20%20axisFormat%20%25b%20%25d%0A%0A%20%20%20%20section%20Audit%0A%20%20%20%20NLPM%20audit%20(157%20artifacts%2C%2079%2F100)%20%20%20%20%3Adone%2C%202026-04-16%2C%201d%0A%0A%20%20%20%20section%20Issue%0A%20%20%20%20Issue%20%23298%20filed%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Amilestone%2C%202026-04-20%2C%200d%0A%20%20%20%20Issue%20%23298%20closed%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Amilestone%2C%202026-04-22%2C%200d%0A%0A%20%20%20%20section%20Response%0A%20%20%20%20v9.26.0%20%E2%80%94%20NLPM%20audit%20fixes%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%202026-04-21%2C%201d%0A%20%20%20%20PRs%20%23293%E2%80%93%23296%20(individual%20fixes)%20%20%20%20%20%20%20%3Adone%2C%202026-04-21%2C%201d%0A%20%20%20%20v9.28.0%20%E2%80%94%20QA%20hardening%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%202026-04-22%2C%201d%0A%20%20%20%20v9.29.1%20%E2%80%94%20patch%20bundle%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%202026-04-22%2C%201d%0A%20%20%20%20v9.29.2%20%E2%80%94%20codex%20exec%20fix%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%202026-04-23%2C%201d%0A%0A%20%20%20%20section%20Verify%0A%20%20%20%20Re-audit%20at%20HEAD%20(127%20artifacts%2C%2082%2F100)%20%3Adone%2C%202026-04-24%2C%201d%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[n(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=d('<hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>The audit and re-audit score NL artifact quality against NLPM&#39;s rubric. They do not run the plugin or evaluate runtime behavior. A score of 82 does not mean the plugin executes correctly.</li><li>All 23 original findings are marked as fixed in the verification table. This reflects fingerprint matching against file content at HEAD; it does not verify semantic completeness or guarantee the underlying issue cannot recur.</li><li>The re-audit does not prove that maintainer intent aligns with NLPM&#39;s rule set. The <code>config/</code> schema findings and <code>allowed-tools</code> compliance gaps reflect NLPM conventions, not the project&#39;s own documented standards. A maintainer who disagrees with the rule is not wrong to reject the finding.</li><li>The 12 introduced findings cannot be definitively attributed to regressions or model drift without audit snapshots from between 2026-04-16 and 2026-04-24.</li><li>Artifact count dropped from 157 to 127 between audit and re-audit. Some &quot;fixed&quot; findings may reflect removed or renamed artifacts rather than corrected content.</li><li>No PR-level review dialogue is on record. The maintainer&#39;s intent behind each fix is inferred from commit messages, not direct discussion.</li><li>The re-audit measures file-level quality at one point in time; it does not verify that maintainer intent aligns with our rule set, and it cannot confirm whether the two open HIGH security findings represent an accepted risk or an overlooked gap.</li></ul><hr><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>claude-octopus received a single audit issue at 18:31 UTC on 2026-04-20 and shipped fixes that the re-audit verified across all 23 original findings — the fastest turnaround we have recorded to date in this pipeline. The engagement demonstrates that a structured issue, without any accompanying pull requests, can prompt meaningful upstream change when the maintainer is actively shipping. The two HIGH security findings in <code>skills/skill-claw/SKILL.md</code> remain open as of 2026-04-24; that unresolved surface is the clearest remaining gap in an otherwise responsive codebase. Twenty-three doors closed in a weekend; two still need keys.</p>',6))])}const x=c(p,[["render",m]]);export{k as __pageData,x as default};
